sql:
SELECT driver_id, AVG(avg_lap_time) AS average_lap_time
FROM leaderboards
GROUP BY driver_id;

SELECT country, COUNT(driver_id) AS driver_count
FROM drivers
GROUP BY country;

external_knowledge:
- 'racers' refers to drivers in the context of the database;
- 'unique ID' refers to the `driver_id` column;
- 'nickname' refers to the `alias` of the driver;
- 'official entries' refer to submissions with `submission_type` as 'official'.

sql:
SELECT COUNT(*) AS total_standings
FROM driver_standings
WHERE event_id = 1;

SELECT COUNT(driver_id) AS driver_count
FROM drivers
WHERE country = 'USA';
